#include <bits/stdc++.h>
using namespace std;;

const int N = 1e6 + 5;
int n, m, c[N], p[N], t[N], ans[N];

struct Q
{
    int x, y, id;
}q[N];

bool cmp(Q x, Q y)
{
    return x.y < y.y;
}

int lowbit(int x)
{
    return x & -x;
}

void add(int x, int k)
{
    for(; x <= n; x += lowbit(x))
        c[x] += k;
}

int getsum(int x)
{
    int sum = 0;
    for(; x; x -= lowbit(x))
        sum += c[x];
    return sum;
}

int main()
{
    ios::sync_with_stdio(false);
    cin.tie(0);
    cin >> n;
    for(int i = 1; i <= n; i++)
    {
        int a;
        cin >> a;
        if(t[a] != 0) p[i] = t[a];
        t[a] = i;
    }
    cin >> m;
    for(int i = 1; i <= m; i++)
    {
        cin >> q[i].x >> q[i].y;
        q[i].id = i;
    }
    sort(q + 1, q + m + 1, cmp);
    int tmp = 1;
    for(int i = 1; i <= m; i++)
    {
        for(int j = tmp; j <= q[i].y; j++)
        {
            if(p[j]) add(p[j], -1);
            add(j, 1);
        }
        tmp = q[i].y + 1;
        ans[q[i].id] = getsum(q[i].y) - getsum(q[i].x - 1);
    }
    for(int i = 1; i <= m; i++)
        cout << ans[i] << endl;
    return 0;
}
